  1→import { useFocusEffect } from '@react-navigation/native';
  2→import type { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
  3→import type { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
  4→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  5→import {
  6→  InteractionManager,
  7→  NativeScrollEvent,
  8→  NativeSyntheticEvent,
  9→} from 'react-native';
 10→import { useShallow } from 'zustand/react/shallow';
 11→import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
 12→import { useRootStore } from '~/store';
 13→import useDebounce from '../../hooks/useDebounce';
 14→import {
 15→  getPointsBalance,
 16→  getPointsExtract,
 17→  PERIOD_DAYS_MAP,
 18→  PointsBalanceStatus,
 19→  PointsExtractStatus,
 20→  processPointsExtractData,
 21→  type AppliedFilters,
 22→  type PointsTransaction,
 23→} from '../../services';
 24→import { EXTRACT_CONSTANTS } from '../../services/constants';
 25→import { ANALYTICS_EVENTS, SCREEN_STRINGS } from './data';
 26→import type {
 27→  ExtractRewardProgramProps,
 28→  FilterGroup,
 29→  UseExtractRewardProgramReturn,
 30→} from './Models';
 31→
 32→import {
 33→  getFilteredTransactions,
 34→  getFilteredTransactionsByText,
 35→} from './utils';
 36→
 37→const SCROLL_THRESHOLD = 300;
 38→
 39→export function useExtractRewardProgramScreen(
 40→  params?: ExtractRewardProgramProps,
 41→): UseExtractRewardProgramReturn {
 42→  const hasTrackedScreenView = useRef(false);
 43→  const hasTrackedSearchPress = useRef(false);
 44→  const canLoadMoreRef = useRef(false);
 45→  const isLoadingMoreRef = useRef(false);
 46→
 47→  const modalizeRefInfo = useRef<PropsModalizeRef>(
 48→    null as unknown as PropsModalizeRef,
 49→  );
 50→  const modalizeRefFilters = useRef<PropsModalizeRef>(
 51→    null as unknown as PropsModalizeRef,
 52→  );
 53→
 54→  const [isRefreshing, setIsRefreshing] = useState(false);
 55→  const [transactionsData, setTransactionsData] = useState<
 56→    propsItemsListCardTransition[]
 57→  >([]);
 58→  const [searchText, setSearchText, debouncedSearchText] = useDebounce('', 400);
 59→
 60→  const {
 61→    pointsExtract,
 62→    pointsBalance,
 63→    pointsExtractFilters,
 64→    pointsExtractActions,
 65→  } = useRootStore(
 66→    useShallow(state => ({
 67→      pointsExtract: state.pointsExtract,
 68→      pointsBalance: state.pointsBalance,
 69→      pointsExtractFilters: state.pointsExtractFilters,
 70→      pointsExtractActions: state.pointsExtractActions,
 71→    })),
 72→  );
 73→
 74→  const isLoadingExtract = pointsExtract.status === PointsExtractStatus.LOADING;
 75→  const isLoadingMore = pointsExtract.isLoadingMore;
 76→  const isLoadingBalance = pointsBalance.status === PointsBalanceStatus.LOADING;
 77→  const appliedTransactionsFilters =
 78→    pointsExtractFilters.appliedTransactionsFilters;
 79→  const hasError =
 80→    pointsExtract.status === PointsExtractStatus.ERROR &&
 81→    !isLoadingExtract &&
 82→    (!pointsExtract.extractData ||
 83→      !pointsExtract.extractData.transactions?.length);
 84→
 85→  useFocusEffect(
 86→    useCallback(() => {
 87→      if (!hasTrackedScreenView.current) {
 88→        eventScreenViewV3(
 89→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_name,
 90→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_class,
 91→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_bussines,
 92→          {
 93→            location_1: ANALYTICS_EVENTS.SCREEN_VIEW.location_1,
 94→            location_2: ANALYTICS_EVENTS.SCREEN_VIEW.location_2,
 95→            location_3: ANALYTICS_EVENTS.SCREEN_VIEW.location_3,
 96→          },
 97→        );
 98→        hasTrackedScreenView.current = true;
 99→      }
100→
101→      return () => {
102→        hasTrackedScreenView.current = false;
103→      };
104→    }, []),
105→  );
106→
107→  const refreshExtractData = useCallback(() => {
108→    pointsExtractActions.setExtractStatus(PointsExtractStatus.IDLE);
109→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
110→    pointsExtractActions.setLoadingMore(false);
111→    getPointsBalance();
112→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
113→  }, [pointsExtractActions]);
114→
115→  useFocusEffect(
116→    useCallback(() => {
117→      refreshExtractData();
118→    }, [refreshExtractData]),
119→  );
120→
121→  useEffect(() => {
122→    const shouldFetchBalance =
123→      pointsBalance.points === undefined ||
124→      pointsBalance.status === PointsBalanceStatus.ERROR;
125→
126→    if (shouldFetchBalance) {
127→      getPointsBalance();
128→    }
129→
130→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
131→  }, [
132→    pointsBalance.points,
133→    pointsBalance.status,
134→  ]);
135→
136→  useEffect(() => {
137→    if (!isLoadingExtract && isRefreshing) {
138→      setIsRefreshing(false);
139→    }
140→  }, [
141→    isLoadingExtract,
142→    isRefreshing,
143→  ]);
144→
145→  useEffect(() => {
146→    if (searchText.length === 0) {
147→      hasTrackedSearchPress.current = false;
148→    }
149→  }, [searchText]);
150→
151→  const getPointsAvailable = useMemo(() => {
152→    return pointsBalance.points ?? 0;
153→  }, [pointsBalance.points]);
154→
155→  const handleGoBack = useCallback(() => {
156→    params?.navigation?.goBack();
157→  }, [params?.navigation]);
158→
159→  const requestPointsExtract = useCallback(() => {
160→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
161→  }, []);
162→
163→  const handleLoadMore = useCallback(() => {
164→    const currentPage = pointsExtract.extractData?.pagination?.page ?? 1;
165→    const totalPages = pointsExtract.extractData?.pagination?.totalPages ?? 1;
166→    const canLoadMore =
167→      currentPage < totalPages && !pointsExtract.isLoadingMore;
168→
169→    if (canLoadMore) {
170→      getPointsExtract({ page: currentPage + 1 });
171→    }
172→  }, [
173→    pointsExtract.extractData?.pagination,
174→    pointsExtract.isLoadingMore,
175→  ]);
176→
177→  const setTransactionsFilters = useCallback(
178→    (filters: AppliedFilters) => {
179→      pointsExtractActions.setTransactionsFilters(filters);
180→    },
181→    [pointsExtractActions],
182→  );
183→
184→  const clearTransactionsFilters = useCallback(() => {
185→    pointsExtractActions.clearTransactionsFilters();
186→  }, [pointsExtractActions]);
187→
188→  const getTransactionsWithFilters = useCallback(
189→    (transactions: PointsTransaction[]): PointsTransaction[] => {
190→      let filtered = transactions;
191→
192→      if (appliedTransactionsFilters) {
193→        const filtersWithDays: AppliedFilters = {
194→          ...appliedTransactionsFilters,
195→          period:
196→            appliedTransactionsFilters.period !== undefined
197→              ? PERIOD_DAYS_MAP[appliedTransactionsFilters.period]
198→              : undefined,
199→        };
200→        filtered = getFilteredTransactions(filtered, filtersWithDays);
201→      }
202→
203→      return filtered;
204→    },
205→    [appliedTransactionsFilters],
206→  );
207→
208→  const getExtractData = useMemo(() => {
209→    if (!pointsExtract.extractData) return undefined;
210→
211→    const transactions = getTransactionsWithFilters(
212→      pointsExtract.extractData.transactions,
213→    );
214→
215→    return {
216→      ...pointsExtract.extractData,
217→      transactions,
218→    };
219→  }, [
220→    pointsExtract.extractData,
221→    getTransactionsWithFilters,
222→  ]);
223→
224→  const getTransactionsData = useMemo(() => {
225→    if (!getExtractData?.transactions) {
226→      return [];
227→    }
228→
229→    if (debouncedSearchText && debouncedSearchText.trim() !== '') {
230→      return getFilteredTransactionsByText(
231→        getExtractData.transactions,
232→        debouncedSearchText,
233→        false,
234→      );
235→    }
236→
237→    return getExtractData.transactions;
238→  }, [
239→    getExtractData?.transactions,
240→    debouncedSearchText,
241→  ]);
242→
243→  useEffect(() => {
244→    if (!getExtractData) return;
245→
246→    let cancelled = false;
247→    const task = InteractionManager.runAfterInteractions(() => {
248→      if (cancelled) return;
249→      const processed = processPointsExtractData({
250→        transactions: getTransactionsData,
251→        pagination: getExtractData.pagination ?? {
252→          page: 1,
253→          pageSize: 100,
254→          total: 0,
255→          totalPages: 0,
256→        },
257→      });
258→      if (!cancelled) {
259→        setTransactionsData(processed.mappedTransactions);
260→      }
261→    });
262→
263→    return () => {
264→      cancelled = true;
265→      task.cancel();
266→    };
267→  }, [
268→    getExtractData,
269→    getTransactionsData,
270→  ]);
271→
272→  const getActiveFiltersCount = useMemo(() => {
273→    let count = 0;
274→    if (
275→      appliedTransactionsFilters?.period !== undefined &&
276→      appliedTransactionsFilters?.period !== null
277→    ) {
278→      count++;
279→    }
280→    if (appliedTransactionsFilters?.types?.length) count++;
281→    return count > 0 ? count.toString() : undefined;
282→  }, [appliedTransactionsFilters]);
283→
284→  const getTransactionsEmptyMessage = useMemo(() => {
285→    const hasSearchText =
286→      debouncedSearchText && debouncedSearchText.trim() !== '';
287→    const hasActiveFilters =
288→      (appliedTransactionsFilters?.period !== undefined &&
289→        appliedTransactionsFilters?.period !== null) ||
290→      (appliedTransactionsFilters?.types?.length ?? 0) > 0;
291→    return hasSearchText || hasActiveFilters
292→      ? SCREEN_STRINGS.EMPTY_SEARCH_RESULTS
293→      : SCREEN_STRINGS.EMPTY_ALL_LIST;
294→  }, [
295→    debouncedSearchText,
296→    appliedTransactionsFilters,
297→  ]);
298→
299→  const getShouldShowTransactionsList =
300→    isLoadingExtract || transactionsData.length > 0;
301→
302→  const canLoadMore =
303→    pointsExtract.extractData?.pagination &&
304→    pointsExtract.extractData.pagination.page <
305→      pointsExtract.extractData.pagination.totalPages;
306→
307→  useEffect(() => {
308→    canLoadMoreRef.current = !!canLoadMore;
309→  }, [canLoadMore]);
310→
311→  useEffect(() => {
312→    isLoadingMoreRef.current = isLoadingMore;
313→  }, [isLoadingMore]);
314→
315→  const handleSearchChange = useCallback(
316→    (text: string) => {
317→      setSearchText(text);
318→    },
319→    [setSearchText],
320→  );
321→
322→  const handleRefresh = useCallback(() => {
323→    setIsRefreshing(true);
324→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
325→    getPointsBalance();
326→    requestPointsExtract();
327→  }, [
328→    requestPointsExtract,
329→    pointsExtractActions,
330→  ]);
331→
332→  const handleError = useCallback(() => {
333→    requestPointsExtract();
334→  }, [requestPointsExtract]);
335→
336→  const handleScroll = useCallback(
337→    (event: NativeSyntheticEvent<NativeScrollEvent>) => {
338→      const { layoutMeasurement, contentOffset, contentSize } =
339→        event.nativeEvent;
340→      const distanceFromBottom =
341→        contentSize.height - layoutMeasurement.height - contentOffset.y;
342→
343→      if (
344→        distanceFromBottom < SCROLL_THRESHOLD &&
345→        canLoadMoreRef.current &&
346→        !isLoadingMoreRef.current
347→      ) {
348→        handleLoadMore();
349→      }
