import React from 'react';
import { NavigationContainer } from '@react-navigation/native';

const navTheme = {
  dark: false,
  colors: {
    primary: '#6200ee',
    background: '#ffffff',
    card: '#ffffff',
    text: '#000000',
    border: '#cccccc',
    notification: '#ff0000',
  },
  fonts: {
    regular: { fontFamily: 'Ubuntu', fontWeight: '400' as const },
    medium: { fontFamily: 'Ubuntu-Medium', fontWeight: '500' as const },
    bold: { fontFamily: 'Ubuntu-Bold', fontWeight: '700' as const },
    heavy: { fontFamily: 'Ubuntu-Bold', fontWeight: '900' as const },
  },
};

const initialState = {
  index: 0,
  routes: [{ name: 'StoryScreen', key: 'StoryScreen-0' }],
};

export function NavigationDecorator(Story: React.ComponentType) {
  return (
    <NavigationContainer
      theme={navTheme as any}
      initialState={initialState}
      independent
    >
      <Story />
    </NavigationContainer>
  );
}

