import { Dispatch, SetStateAction } from 'react';

import { PropsIconsNameCore } from '../../../../styles/Models/type.icon';
import {
  PropsSpacesHorizontalCore,
  PropsSpacesVerticalCore,
} from '../../../../styles/Models/type.spaces';

export type typesCardTransition =
  | 'default'
  | 'checkbox'
  | 'specific'
  | 'specific-button';

export interface PropsCardTransition {
  mt?: PropsSpacesHorizontalCore;
  mb?: PropsSpacesHorizontalCore;
  ml?: PropsSpacesVerticalCore;
  mr?: PropsSpacesVerticalCore;
  testID?: string;
  type?: typesCardTransition;
  showIcon?: boolean;
  leftIcon?: PropsIconsNameCore;
  leftIconColor?: propsAllowedIconColors;
  showBackgroundLeftIcon?: boolean;
  backgroundLeftIconColor?: propsAllowedBgIconColors;
  title?: string;
  titleColor?: propsAllowedTextColors;
  titleType?: propsAllowedTitleTextTypes;
  description?: string;
  descriptionColor?: propsAllowedTextColors;
  descriptionSecondary?: string;
  descriptionSecondaryColor?: propsAllowedTextColors;
  descriptionSecondaryType?: propsAllowedDescriptionSecondaryTypes;
  value?: string;
  valueColor?: propsAllowedTextColors;
  valueType?: propsAllowedValueTypeText;
  showRightIcon?: boolean;
  rightIcon?: PropsIconsNameCore;
  label?: string;
  labelBgColor: propsAllowedLabelBgColors;
  isSelected?: boolean;
  showLabel?: boolean;
  disabled?: boolean;
  disabledOnPressLabel?: boolean;
  disableButton?: boolean;
  bgColor?: propsAllowedBgColors;
  buttonType?: 'primaryNano' | 'secondaryNano';
  buttonText?: string;
  onPressLabel?: () => void;
  onChangeCheckBox?: (value: boolean) => void;
  onPress?: (value: boolean) => void;
  onPressButton?: () => void;
  showTagLabel?: boolean;
  tagLabelText?: string;
  tagLabelType?: string;
  tagLabelHighlight?: boolean;
  tagLabelIcon?: PropsIconsNameCore;
  detail?: string;
  secondaryValue?: string;
  lineThrough?: boolean;
  onPressDetail?: () => void;
}

export interface PropsCardTransitionView extends PropsCardTransition {
  allowedTitleTextTypes: (
    type: propsAllowedTitleTextTypes,
  ) => propsAllowedTitleTextTypes;
  allowedValueTypeText: (
    type: propsAllowedValueTypeText,
  ) => propsAllowedValueTypeText;
  allowedDescriptionSecondaryType: (
    type: propsAllowedDescriptionSecondaryTypes,
  ) => propsAllowedDescriptionSecondaryTypes;
  allowedLabelBgColor: (
    color: propsAllowedLabelBgColors,
  ) => propsAllowedLabelBgColors;
  allowedIconColors: (color: propsAllowedIconColors) => propsAllowedIconColors;
  allowedBgIconColors: (
    color: propsAllowedBgIconColors,
  ) => propsAllowedBgIconColors;
  allowedTextColors: (color: propsAllowedTextColors) => propsAllowedTextColors;
  allowedBgColors: (color: propsAllowedBgColors) => propsAllowedBgColors;
  getType: () => void;
  selected: boolean;
  setSelected: Dispatch<SetStateAction<boolean>>;
}

export enum ALLOWED_DESCRIPTION_SECONDARY_TYPES {
  paragraphSM = 'paragraphSM',
  paragraphMDM = 'paragraphMDM',
}

export enum ALLOWED_TITLE_TEXT_TYPES {
  paragraphMDM = 'paragraphMDM',
  paragraphXL = 'paragraphXL',
}

export enum ALLOWED_TEXT_COLORS {
  BRAND_COMPLEMENT_01 = 'BRAND_COMPLEMENT_01',
  PLUS_COLOR_02 = 'PLUS_COLOR_02',
  DENY_COLOR_02 = 'DENY_COLOR_02',
  EMPHASIS_COLOR_02 = 'EMPHASIS_COLOR_02',
  INTENSE_COLOR_04 = 'INTENSE_COLOR_04',
  INTENSE_COLOR_05 = 'INTENSE_COLOR_05',
}

export enum ALLOWED_ICON_COLORS {
  BRAND_COMPLEMENT_01 = 'BRAND_COMPLEMENT_01',
  PLUS_COLOR_02 = 'PLUS_COLOR_02',
