    state.pointsExtractActions.setBalance(points);
    state.pointsExtractActions.setExtractData(MOCK_EXTRACT_DATA);
  }
}

function seedStoreLoading() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.LOADING);
    state.pointsExtractActions.setBalanceStatus(PointsBalanceStatus.LOADING);
  }
}

function seedStoreError() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.ERROR);
    state.pointsExtractActions.setBalance(0);
  }
}

function seedStoreEmpty(points: number) {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setBalance(points);
    state.pointsExtractActions.setExtractData({
      transactions: [],
      pagination: { page: 1, pageSize: 20, total: 0, totalPages: 0 },
    });
  }
}

function EmptyList({ label }: { label: string }) {
  return (
    <Box width="100%" justify="center" align="center">
      <Icon
        name="icon-invoice-error"
        size="lg"
        color="INTENSE_COLOR_02"
        mt="meddium"
      />
      <Text
        type="paragraphLG"
        pd="innerGreat"
        color="INTENSE_COLOR_03"
        align="center"
      >
        {label}
      </Text>
    </Box>
  );
}

function TransactionsList({
  items,
  isLoading,
}: {
  items: propsItemsListCardTransition[];
  isLoading: boolean;
}) {
  return (
    <ListCardTransition
      items={items}
      isLoading={isLoading}
      scrollEnabled={false}
      mb="meddium"
    />
  );
}

function ErrorState({ onRetry }: { onRetry: () => void }) {
  return (
    <Box flex={1} justify="center" align="center" pd="innerLarge">
      <Icon name="icon-circle-alert" color="DENY_COLOR_01" size={48} />
      <Text type="paragraphXXXL" align="center" mt="smaller" mb="xxxs">
        Algo deu errado!
      </Text>
      <Text
        type="paragraphMD"
        align="center"
        color="INTENSE_COLOR_05"
        mb="smaller"
      >
        Por favor, tente de novo.
      </Text>
    </Box>
  );
}

function ExtractStoryWrapper({
  points = 15320,
  isLoading = false,
  hasError = false,
  isEmpty = false,
}: {
  points?: number;
  isLoading?: boolean;
  hasError?: boolean;
  isEmpty?: boolean;
}) {
  const [transactionsData, setTransactionsData] = React.useState<
    propsItemsListCardTransition[]
  >([]);

  useEffect(() => {
    if (hasError) {
      seedStoreError();
      return;
    }
    if (isLoading) {
      seedStoreLoading();
      return;
    }
    if (isEmpty) {
      seedStoreEmpty(points);
      return;
    }
    seedStoreLoaded(points);
  }, [points, isLoading, hasError, isEmpty]);

  useEffect(() => {
    if (!isLoading && !hasError && !isEmpty) {
      const processed = processPointsExtractData(MOCK_EXTRACT_DATA);
      setTransactionsData(processed.mappedTransactions);
    } else if (isEmpty) {
      setTransactionsData([]);
    }
  }, [isLoading, hasError, isEmpty]);

  if (hasError) {
    return (
      <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
        <Header
          title="Extrato"
          iconLeft="icon-back"
          hideLeftIcon={false}
          onBack={() => {}}
        />
        <ErrorState onRetry={() => {}} />
      </Box>
    );
  }

  const showTransactionsList = isLoading || transactionsData.length > 0;

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Extrato"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
          <CardPoints
            icon="icon-benefits"
            iconInfo="icon-help"
            title="Pontos disponíveis"
            valuePoints={
              !isLoading && points
                ? Math.floor(points).toLocaleString('pt-br')
                : '0'
            }
            hideBottom
            isLoading={isLoading}
            onPressIconInfo={() => {}}
          />

          <Text
            type="paragraphXXXL"
            mb="xxxxs"
            mt="xxs"
            color="INTENSE_COLOR_05"
          >
            Lançamentos
          </Text>

          <SeparatorHorizontal
            borderWidth="smaller"
            borderColor="BRAND_COMPLEMENT_02"
            height={1}
            mb="xxxxs"
            width="100%"
          />
          <SearchUsed
            placeholder="Buscar por pontos, tipos de compra etc"
            onChangeText={() => {}}
            value=""
            showIcon={false}
            firstIcon={undefined}
            onPressIn={() => {}}
            numberIcon={undefined}
            secondIcon="icon-filter-settings"
            secondOnPress={() => {}}
            showFilter
          />
        </Box>

        <Box
          ml={isLoading ? 'xs' : 'none'}
          mr={isLoading ? 'xs' : 'none'}
        >
          <Tabs
            items={[
              {
                id: 0,
                title: 'Todos',
                component: (
                  <TransactionsList
                    items={transactionsData}
                    isLoading={isLoading}
                  />
                ),
              },
              {
                id: 1,
                title: 'A expirar',
                component: <></>,
              },
            ]}
            showBackground={false}
            hasScroll={false}
            loadingType="light"
            onChange={() => {}}
            type="options"
            isLoading={isLoading}
          />
          {!showTransactionsList && (
            <EmptyList
              label={
                isEmpty
                  ? 'Para ganhar pontos, use seu cartão Sem Parar Mais ou a Tag.'
                  : 'Não encontramos resultados para sua busca.'
              }
            />
          )}
        </Box>
      </ScrollView>
    </Box>
  );
}

const meta: Meta<typeof ExtractStoryWrapper> = {
  title: 'Screens/Extract',
  component: ExtractStoryWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    points: {
      control: { type: 'number' },
      description: 'Available points balance',
    },
    isLoading: {
      control: { type: 'boolean' },
      description: 'Loading skeleton state',
    },
    hasError: {
      control: { type: 'boolean' },
      description: 'API error state',
    },
    isEmpty: {
      control: { type: 'boolean' },
      description: 'Empty transactions state',
    },
  },
};

export default meta;
type Story = StoryObj<typeof ExtractStoryWrapper>;

export const Loaded: Story = {
  name: 'Loaded (8 transactions)',
  args: { points: 15320, isLoading: false },
};

export const Empty: Story = {
  name: 'Empty State',
  args: { points: 500, isEmpty: true },
};

export const Loading: Story = {
  name: 'Loading State',
  args: { points: 0, isLoading: true },
};

export const Error: Story = {
  name: 'Error State',
  args: { hasError: true },
};

