import React, { useEffect } from 'react';
import { ScrollView } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Box,
  CardPoints,
  Header,
  Icon,
  ListCardTransition,
  LoadingFooter,
  SearchUsed,
  SeparatorHorizontal,
  Tabs,
  Text,
} from '@semparar/design-system-app';
import type { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';
import { useRootStore } from '~/store';
import {
  PointsExtractStatus,
  PointsBalanceStatus,
} from '../services/models/extract.model';
import { processPointsExtractData } from '../services/repository/extract.repository';
import type {
  PointsTransaction,
  PointsExtractData,
} from '../services/models/extract.model';

const MOCK_TRANSACTIONS: PointsTransaction[] = [
  {
    id: '1',
    date: '2026-02-20T14:30:00Z',
    description: 'Pedágio Rodovia Anhanguera',
    type: 'CREDIT',
    amount: 150,
    currencyValue: 1.5,
    icon: 'icon-tag',
    details: { provider: 'Sem Parar', extraInfo: '', fields: [] },
    status: 'CONFIRMED',
  },
  {
    id: '2',
    date: '2026-02-20T10:15:00Z',
    description: 'Estacionamento Shopping Morumbi',
    type: 'CREDIT',
    amount: 80,
    currencyValue: 0.8,
    icon: 'icon-parking',
    details: { provider: 'Sem Parar', extraInfo: '', fields: [] },
    status: 'CONFIRMED',
  },
  {
    id: '3',
    date: '2026-02-18T16:45:00Z',
    description: 'Voucher Abastecimento',
    type: 'RESCUE',
    amount: 500,
    currencyValue: 5.0,
    icon: 'icon-gas-station',
    details: { provider: 'Shell', extraInfo: '', fields: [] },
    status: 'CONFIRMED',
  },
  {
    id: '4',
    date: '2026-02-18T09:00:00Z',
    description: 'Pedágio Rodovia dos Bandeirantes',
    type: 'CREDIT',
    amount: 200,
    currencyValue: 2.0,
    icon: 'icon-tag',
    details: { provider: 'Sem Parar', extraInfo: '', fields: [] },
    status: 'CONFIRMED',
  },
  {
    id: '5',
    date: '2026-02-15T11:30:00Z',
    description: 'Pontos expirados',
    type: 'EXPIRED',
    amount: 320,
    currencyValue: 3.2,
    icon: 'icon-less',
    details: { provider: '', extraInfo: '', fields: [] },
    status: 'EXPIRED',
  },
  {
    id: '6',
    date: '2026-02-12T08:00:00Z',
    description: 'Cashback na fatura',
    type: 'RESCUE',
    amount: 1000,
    currencyValue: 10.0,
    icon: 'icon-invoice',
    details: { provider: 'Sem Parar', extraInfo: '', fields: [] },
    status: 'CONFIRMED',
  },
  {
    id: '7',
    date: '2026-02-12T14:20:00Z',
    description: 'Pedágio Via Dutra',
    type: 'CREDIT',
    amount: 120,
    currencyValue: 1.2,
    icon: 'icon-tag',
    details: { provider: 'Sem Parar', extraInfo: '', fields: [] },
    status: 'CONFIRMED',
  },
  {
    id: '8',
    date: '2026-02-10T09:45:00Z',
    description: 'Estorno voucher',
    type: 'REFUNDED',
    amount: 250,
    currencyValue: 2.5,
    icon: 'icon-transfer',
    details: { provider: 'Sem Parar', extraInfo: '', fields: [] },
    status: 'REFUNDED',
  },
];

const MOCK_EXTRACT_DATA: PointsExtractData = {
  transactions: MOCK_TRANSACTIONS,
  pagination: {
    page: 1,
    pageSize: 20,
    total: 8,
    totalPages: 1,
  },
};

function seedStoreLoaded(points: number) {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setBalance(points);
    state.pointsExtractActions.setExtractData(MOCK_EXTRACT_DATA);
  }
}

function seedStoreLoading() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.LOADING);
    state.pointsExtractActions.setBalanceStatus(PointsBalanceStatus.LOADING);
  }
}

function seedStoreError() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.ERROR);
    state.pointsExtractActions.setBalance(0);
  }
}

function seedStoreEmpty(points: number) {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setBalance(points);
    state.pointsExtractActions.setExtractData({
      transactions: [],
      pagination: { page: 1, pageSize: 20, total: 0, totalPages: 0 },
    });
  }
}

function EmptyList({ label }: { label: string }) {
  return (
    <Box width="100%" justify="center" align="center">
      <Icon
        name="icon-invoice-error"
        size="lg"
        color="INTENSE_COLOR_02"
        mt="meddium"
      />
      <Text
        type="paragraphLG"
        pd="innerGreat"
        color="INTENSE_COLOR_03"
        align="center"
      >
        {label}
      </Text>
    </Box>
  );
}

function TransactionsList({
  items,
  isLoading,
}: {
  items: propsItemsListCardTransition[];
  isLoading: boolean;
}) {
  return (
    <ListCardTransition
      items={items}
      isLoading={isLoading}
      scrollEnabled={false}
      mb="meddium"
    />
  );
}

function ErrorState({ onRetry }: { onRetry: () => void }) {
  return (
    <Box flex={1} justify="center" align="center" pd="innerLarge">
      <Icon name="icon-circle-alert" color="DENY_COLOR_01" size={48} />
      <Text type="paragraphXXXL" align="center" mt="smaller" mb="xxxs">
        Algo deu errado!
      </Text>
      <Text
        type="paragraphMD"
        align="center"
        color="INTENSE_COLOR_05"
        mb="smaller"
      >
        Por favor, tente de novo.
      </Text>
    </Box>
  );
}

function ExtractStoryWrapper({
  points = 15320,
  isLoading = false,
  hasError = false,
  isEmpty = false,
}: {
  points?: number;
  isLoading?: boolean;
  hasError?: boolean;
  isEmpty?: boolean;
}) {
  const [transactionsData, setTransactionsData] = React.useState<
    propsItemsListCardTransition[]
  >([]);

  useEffect(() => {
    if (hasError) {
      seedStoreError();
      return;
    }
    if (isLoading) {
      seedStoreLoading();
      return;
    }
    if (isEmpty) {
      seedStoreEmpty(points);
      return;
    }
    seedStoreLoaded(points);
  }, [points, isLoading, hasError, isEmpty]);

  useEffect(() => {
    if (!isLoading && !hasError && !isEmpty) {
      const processed = processPointsExtractData(MOCK_EXTRACT_DATA);
      setTransactionsData(processed.mappedTransactions);
    } else if (isEmpty) {
      setTransactionsData([]);
    }
  }, [isLoading, hasError, isEmpty]);

  if (hasError) {
    return (
      <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
        <Header
          title="Extrato"
          iconLeft="icon-back"
          hideLeftIcon={false}
          onBack={() => {}}
        />
        <ErrorState onRetry={() => {}} />
      </Box>
    );
  }

  const showTransactionsList = isLoading || transactionsData.length > 0;

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Extrato"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
          <CardPoints
            icon="icon-benefits"
            iconInfo="icon-help"
            title="Pontos disponíveis"
            valuePoints={
              !isLoading && points
                ? Math.floor(points).toLocaleString('pt-br')
                : '0'
            }
            hideBottom
            isLoading={isLoading}
            onPressIconInfo={() => {}}
          />

          <Text
            type="paragraphXXXL"
            mb="xxxxs"
            mt="xxs"
            color="INTENSE_COLOR_05"
          >
            Lançamentos
          </Text>

          <SeparatorHorizontal
            borderWidth="smaller"
            borderColor="BRAND_COMPLEMENT_02"
            height={1}
            mb="xxxxs"
            width="100%"
          />
          <SearchUsed
            placeholder="Buscar por pontos, tipos de compra etc"
            onChangeText={() => {}}
            value=""
            showIcon={false}
            firstIcon={undefined}
            onPressIn={() => {}}
            numberIcon={undefined}
            secondIcon="icon-filter-settings"
            secondOnPress={() => {}}
            showFilter
          />
        </Box>

        <Box
          ml={isLoading ? 'xs' : 'none'}
          mr={isLoading ? 'xs' : 'none'}
        >
          <Tabs
            items={[
              {
                id: 0,
                title: 'Todos',
                component: (
                  <TransactionsList
                    items={transactionsData}
                    isLoading={isLoading}
                  />
                ),
              },
              {
                id: 1,
                title: 'A expirar',
                component: <></>,
              },
            ]}
            showBackground={false}
            hasScroll={false}
            loadingType="light"
            onChange={() => {}}
            type="options"
            isLoading={isLoading}
          />
          {!showTransactionsList && (
            <EmptyList
              label={
                isEmpty
                  ? 'Para ganhar pontos, use seu cartão Sem Parar Mais ou a Tag.'
                  : 'Não encontramos resultados para sua busca.'
              }
            />
          )}
        </Box>
      </ScrollView>
    </Box>
  );
}

const meta: Meta<typeof ExtractStoryWrapper> = {
  title: 'Screens/Extract',
  component: ExtractStoryWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    points: {
      control: { type: 'number' },
      description: 'Available points balance',
    },
    isLoading: {
      control: { type: 'boolean' },
      description: 'Loading skeleton state',
    },
    hasError: {
      control: { type: 'boolean' },
      description: 'API error state',
    },
    isEmpty: {
      control: { type: 'boolean' },
      description: 'Empty transactions state',
    },
  },
};

export default meta;
type Story = StoryObj<typeof ExtractStoryWrapper>;

export const Loaded: Story = {
  name: 'Loaded (8 transactions)',
  args: { points: 15320, isLoading: false },
};

export const Empty: Story = {
  name: 'Empty State',
  args: { points: 500, isEmpty: true },
};

export const Loading: Story = {
  name: 'Loading State',
  args: { points: 0, isLoading: true },
};

export const Error: Story = {
  name: 'Error State',
  args: { hasError: true },
};

